body {
  -webkit-hyphens: auto; /* For older WebKit browsers */
  -ms-hyphens: auto;    /* For Internet Explorer */
  hyphens: auto;        /* Standard property */
  word-break: break-word; /* Ensure long words don't overflow */
}

/* For best results, ensure the lang attribute is set on the HTML or relevant element, e.g., <html lang="en"> */
.article-content {
  hyphens: auto;
  text-align: justify; /* Often used effectively with hyphens */
  -webkit-hyphens: auto;
  -ms-hyphens: auto;
}
